import{c as a,S as t,j as n,m as i}from"./chunks/framework.CjWqT1Z0.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":null}'),o={name:"changelog.md"};function r(l,e,s,c,d,g){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="Changelog" tabindex="-1">Changelog <a class="header-anchor" href="#Changelog" aria-label="Permalink to &quot;Changelog {#Changelog}&quot;">​</a></h1><p>Notable changes to GLLVM.jl. Style mirrors <code>gllvmTMB</code>&#39;s NEWS: status labels <strong>IN</strong> (shipped), <strong>PARTIAL</strong> (limited), <strong>PLANNED</strong> (next), with issue/PR refs.</p><h2 id="GLLVM.jl-development-version" tabindex="-1">GLLVM.jl (development version) <a class="header-anchor" href="#GLLVM.jl-development-version" aria-label="Permalink to &quot;GLLVM.jl (development version) {#GLLVM.jl-development-version}&quot;">​</a></h2><h3 id="Documentation" tabindex="-1">Documentation <a class="header-anchor" href="#Documentation" aria-label="Permalink to &quot;Documentation {#Documentation}&quot;">​</a></h3><ul><li><strong>IN:</strong> pkgdown-style documentation site (DocumenterVitepress) — dropdown navbar, full-text search, light/dark mode; homepage mirrors <code>gllvmTMB</code>&#39;s with a Julia flavour. (#4)</li></ul><h3 id="Engine" tabindex="-1">Engine <a class="header-anchor" href="#Engine" aria-label="Permalink to &quot;Engine {#Engine}&quot;">​</a></h3><ul><li><p><strong>IN:</strong> O(p) node-frame phylogenetic gradient; type-stable recursion kernels (function barrier + parametric state); Aqua + JET quality gates wired green.</p></li><li><p><strong>PLANNED:</strong> an at-scale phylogenetic fitter <code>fit_phylo_gaussian</code> over the O(p) gradient. (#5)</p></li></ul><h3 id="Quality-and-infrastructure" tabindex="-1">Quality &amp; infrastructure <a class="header-anchor" href="#Quality-and-infrastructure" aria-label="Permalink to &quot;Quality &amp; infrastructure {#Quality-and-infrastructure}&quot;">​</a></h3><ul><li><p><strong>IN:</strong> <code>Pkg.test()</code> adopted as the full-suite command; Aqua (package hygiene) and JET (type-stability of the O(p) kernels) run in CI.</p></li><li><p><strong>IN:</strong> isolated RCall.jl parity scaffold (<code>test/parity/</code>, opt-in) for checking agreement against R <code>gllvmTMB</code>.</p></li></ul><h2 id="GLLVM.jl-v0.1.0" tabindex="-1">GLLVM.jl v0.1.0 <a class="header-anchor" href="#GLLVM.jl-v0.1.0" aria-label="Permalink to &quot;GLLVM.jl v0.1.0 {#GLLVM.jl-v0.1.0}&quot;">​</a></h2><ul><li><p><strong>IN:</strong> Gaussian + phylogenetic GLLVM engine — closed-form marginal likelihood, PPCA / EM initialisation, multiple phylogenetic representations (sparse precision, Felsenstein contrasts, edge-incidence) agreeing to machine precision.</p></li><li><p><strong>IN:</strong> Wald / profile-likelihood / parametric-bootstrap confidence intervals, including derived quantities (Σ_y entries, communality, cross-trait correlation, phylogenetic signal).</p></li><li><p><strong>IN:</strong> ~340× median per-fit speedup over R <code>gllvmTMB</code> on the Gaussian benchmark grid, reproducing estimates and likelihoods to machine precision.</p></li></ul>',11)])])}const h=a(o,[["render",r]]);export{u as __pageData,h as default};
